// FileName is the name of the file, relative to the configured TSDB storage
// directory, under which the most recent reload outcome is persisted.
const FileName = "reload_status.json"

// ErrorCategory is a coarse classification of why a reload attempt failed.
type ErrorCategory string

const (
	// CategoryNone means the last reload succeeded (or none has happened yet).
	CategoryNone ErrorCategory = "none"
	// CategoryLoad means the configuration could not be loaded or parsed.
	CategoryLoad ErrorCategory = "load_error"
	// CategoryApply means a reloader failed to apply the new configuration.
	CategoryApply ErrorCategory = "apply_error"
	// CategoryRollback means a reloader failed while rolling back to the last
	// known-good configuration after an apply error.
	CategoryRollback ErrorCategory = "rollback_error"
)

// Status is the observable outcome of the most recent reload attempt. It is
// the payload served by GET /api/v1/status/reload and the shape persisted to
// disk.
type Status struct {
	// LastReloadID is an RFC3339 timestamp identifying the most recent attempt.
	LastReloadID         string        `json:"last_reload_id"`
	LastReloadSuccessful bool          `json:"last_reload_successful"`
	ErrorCategory        ErrorCategory `json:"error_category"`
	ErrorMessage         string        `json:"error_message"`
	// AppliedReloaders lists the reloaders that successfully applied the new
	// configuration during the attempt, in the order they ran.
	AppliedReloaders   []string `json:"applied_reloaders"`
	RollbackAttempted  bool     `json:"rollback_attempted"`
	RollbackSuccessful bool     `json:"rollback_successful"`
	// FailedReloader is the name of the reloader that failed, if any.
	FailedReloader string `json:"failed_reloader"`
	// ReloaderTimingsMs maps reloader name to the time it took to apply the new
	// configuration, in milliseconds.
	ReloaderTimingsMs map[string]float64 `json:"reloader_timings_ms"`
}

// Default returns the status reported before the first reload attempt: no
// reload has run, so nothing has been applied and there is no error.
func Default() Status {
	return Status{
		LastReloadID:         "",
		LastReloadSuccessful: false,
		ErrorCategory:        CategoryNone,
		ErrorMessage:         "",
		AppliedReloaders:     []string{},
		ReloaderTimingsMs:    map[string]float64{},
	}
}

// normalize replaces nil slices/maps and an empty category with their defaults
// so the JSON representation always uses [] and {} rather than null, and the
// category is always one of the documented values.
func normalize(s Status) Status {
	if s.AppliedReloaders == nil {
		s.AppliedReloaders = []string{}
	}
	if s.ReloaderTimingsMs == nil {
		s.ReloaderTimingsMs = map[string]float64{}
	}
	if s.ErrorCategory == "" {
		s.ErrorCategory = CategoryNone
	}
	return s
}

// Tracker holds the most recent reload outcome, exposes it to readers, and
// persists it durably under the configured storage directory. A Tracker with
// an empty directory keeps state only in memory (useful for tests).
type Tracker struct {
	mtx    sync.RWMutex
	dir    string
	status Status
	logger *slog.Logger
}

// NewTracker returns a Tracker that persists state under dir. It does not read
// any existing state; call Load for that.
func NewTracker(dir string, logger *slog.Logger) *Tracker {
	if logger == nil {
		logger = slog.New(slog.NewTextHandler(os.Stderr, nil))
	}
	return &Tracker{
		dir:    dir,
		status: Default(),
		logger: logger,
	}
}

func (t *Tracker) path() string {
	return filepath.Join(t.dir, FileName)
}

// Load reads any previously persisted status. A missing or corrupted state file
// is ignored: the tracker keeps its default status and Load never fails, so
// startup and the endpoint keep working regardless.
func (t *Tracker) Load() {
	if t.dir == "" {
		return
	}
	b, err := os.ReadFile(t.path())
	if err != nil {
		if !os.IsNotExist(err) {
			t.logger.Warn("Could not read persisted reload status, ignoring", "path", t.path(), "err", err)
		}
		return
	}
	var s Status
	if err := json.Unmarshal(b, &s); err != nil {
		t.logger.Warn("Persisted reload status is corrupted, ignoring", "path", t.path(), "err", err)
		return
	}
	t.mtx.Lock()
	t.status = normalize(s)
	t.mtx.Unlock()
}

// Get returns the most recent reload outcome.
func (t *Tracker) Get() Status {
	t.mtx.RLock()
	defer t.mtx.RUnlock()
	return t.status
}

