}

func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), tx *txReloadState, rls ...reloader) (err error) {
	start := time.Now()
	timingsLogger := logger
	logger.Info("Loading configuration file", "filename", filename)

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			configSuccess.Set(0)
			callback(false)
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		if tx != nil {
			// Config load/parse failure: nothing was applied, so no rollback is
			// attempted. Record the outcome so it is observable and durable.
			st := reloadstatus.Default()
			st.LastReloadID = reloadID()
			st.ErrorCategory = reloadstatus.CategoryLoad
			st.ErrorMessage = err.Error()
			tx.tracker.Set(st)
		}
		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
	}

	if enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	if tx != nil {
		// Transactional mode: run reloaders in sequence, stopping and rolling
		// back on the first failure.
		if err := reloadTransactional(conf, filename, logger, tx, rls); err != nil {
			return err
		}
	} else {
		// Legacy best-effort mode: run every reloader, then fail if any did.
		failed := false
		for _, rl := range rls {
			rstart := time.Now()
			if err := rl.reloader(conf); err != nil {
				logger.Error("Failed to apply configuration", "err", err)
				failed = true
			}
			timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
		}
		if failed {
			return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
		}
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
}

