func TestDefaultMarshalsEmptyCollections(t *testing.T) {
	// Before the first reload the response must use empty (not null) slices and
	// maps and error_category "none".
	b, err := json.Marshal(Default())
	require.NoError(t, err)

	var m map[string]any
	require.NoError(t, json.Unmarshal(b, &m))
	require.Equal(t, "", m["last_reload_id"])
	require.Equal(t, false, m["last_reload_successful"])
	require.Equal(t, "none", m["error_category"])
	require.Equal(t, []any{}, m["applied_reloaders"])
	require.Equal(t, map[string]any{}, m["reloader_timings_ms"])
}

func TestTrackerGetDefault(t *testing.T) {
	tr := NewTracker("", nil)
	require.Equal(t, Default(), tr.Get())
}

func TestTrackerSetPersistsAndReloads(t *testing.T) {
	dir := t.TempDir()
	tr := NewTracker(dir, nil)

	want := Status{
		LastReloadID:         "2026-07-14T00:00:00Z",
		LastReloadSuccessful: false,
		ErrorCategory:        CategoryApply,
		ErrorMessage:         "boom",
		AppliedReloaders:     []string{"db_storage", "remote_storage"},
		RollbackAttempted:    true,
		RollbackSuccessful:   true,
		FailedReloader:       "scrape",
		ReloaderTimingsMs:    map[string]float64{"db_storage": 1.5},
	}
	tr.Set(want)

	// A file must have been written under the directory.
	_, err := os.Stat(filepath.Join(dir, FileName))
	require.NoError(t, err)

	// A fresh tracker over the same directory recovers the outcome.
	tr2 := NewTracker(dir, nil)
	tr2.Load()
	require.Equal(t, want, tr2.Get())
}

func TestTrackerNoFileBeforeFirstSet(t *testing.T) {
	dir := t.TempDir()
	tr := NewTracker(dir, nil)
	tr.Load()

	// Load of a non-existent state file must not create one, and the status
	// stays at the default.
	_, err := os.Stat(filepath.Join(dir, FileName))
	require.True(t, os.IsNotExist(err))
	require.Equal(t, Default(), tr.Get())
}

func TestTrackerCorruptStateIgnored(t *testing.T) {
	dir := t.TempDir()
	require.NoError(t, os.WriteFile(filepath.Join(dir, FileName), []byte("{not json"), 0o644))

	tr := NewTracker(dir, nil)
	tr.Load()
	// Corrupted state must be ignored, leaving the default in place.
	require.Equal(t, Default(), tr.Get())
}

func TestTrackerNormalizesNilCollections(t *testing.T) {
	tr := NewTracker("", nil)
	tr.Set(Status{ErrorCategory: ""})
	got := tr.Get()
	require.Equal(t, CategoryNone, got.ErrorCategory)
	require.NotNil(t, got.AppliedReloaders)
	require.NotNil(t, got.ReloaderTimingsMs)
	require.Empty(t, got.AppliedReloaders)
	require.Empty(t, got.ReloaderTimingsMs)
}
