// stepReloader records the configs it is asked to apply and can be made to fail
// on a chosen 1-based call index (0 = never).
type stepReloader struct {
	name       string
	failOnCall int
	call       int
	configs    []*config.Config
}

func (s *stepReloader) apply(cfg *config.Config) error {
	s.call++
	s.configs = append(s.configs, cfg)
	if s.failOnCall != 0 && s.call >= s.failOnCall {
		return errors.New(s.name + " failed")
	}
	return nil
}

func (s *stepReloader) asReloader() reloader {
	return reloader{name: s.name, reloader: s.apply}
}

func writeConfig(t *testing.T, path, content string) {
	t.Helper()
	require.NoError(t, os.WriteFile(path, []byte(content), 0o644))
}

func doReload(t *testing.T, cfgFile string, tx *txReloadState, rls ...reloader) error {
	t.Helper()
	return reloadConfig(cfgFile, false, promslog.NewNopLogger(), &safePromQLNoStepSubqueryInterval{}, func(bool) {}, tx, rls...)
}

func newTxState(dir string) *txReloadState {
	return &txReloadState{tracker: reloadstatus.NewTracker(dir, nil)}
}

func TestTransactionalReload_Success(t *testing.T) {
	dir := t.TempDir()
	cfgFile := filepath.Join(dir, "prometheus.yml")
	writeConfig(t, cfgFile, "global:\n  scrape_interval: 15s\n")
	tx := newTxState(t.TempDir())

	a := &stepReloader{name: "a"}
	b := &stepReloader{name: "b"}

	require.NoError(t, doReload(t, cfgFile, tx, a.asReloader(), b.asReloader()))

	st := tx.tracker.Get()
	require.True(t, st.LastReloadSuccessful)
	require.Equal(t, reloadstatus.CategoryNone, st.ErrorCategory)
	require.Equal(t, []string{"a", "b"}, st.AppliedReloaders)
	require.False(t, st.RollbackAttempted)
	require.NotEmpty(t, st.LastReloadID)
	require.Contains(t, st.ReloaderTimingsMs, "a")
	require.Contains(t, st.ReloaderTimingsMs, "b")
	require.NotNil(t, tx.lastGood, "a successful reload establishes the last known-good config")
}

func TestTransactionalReload_LoadErrorNoRollback(t *testing.T) {
	dir := t.TempDir()
	cfgFile := filepath.Join(dir, "prometheus.yml")
	writeConfig(t, cfgFile, "global:\n  scrape_interval: 15s\n")
	tx := newTxState(t.TempDir())

	a := &stepReloader{name: "a"}
	// Establish a baseline so a known-good config exists.
	require.NoError(t, doReload(t, cfgFile, tx, a.asReloader()))
	callsBefore := a.call

	// Corrupt the config and reload: load fails before any reloader runs.
	writeConfig(t, cfgFile, "global: [not valid yaml")
	require.Error(t, doReload(t, cfgFile, tx, a.asReloader()))

	st := tx.tracker.Get()
	require.False(t, st.LastReloadSuccessful)
	require.Equal(t, reloadstatus.CategoryLoad, st.ErrorCategory)
	require.NotEmpty(t, st.ErrorMessage)
	require.False(t, st.RollbackAttempted)
	require.Empty(t, st.AppliedReloaders)
	require.Equal(t, callsBefore, a.call, "no reloader (nor rollback) runs on a load error")
}

func TestTransactionalReload_ApplyErrorRollsBack(t *testing.T) {
	dir := t.TempDir()
	cfgFile := filepath.Join(dir, "prometheus.yml")
	writeConfig(t, cfgFile, "global:\n  scrape_interval: 15s\n")
	tx := newTxState(t.TempDir())

	a := &stepReloader{name: "a"}
	b := &stepReloader{name: "b", failOnCall: 2} // succeeds on baseline, fails on the second reload
	c := &stepReloader{name: "c"}

	require.NoError(t, doReload(t, cfgFile, tx, a.asReloader(), b.asReloader(), c.asReloader()))
	goodConfig := tx.lastGood
	require.NotNil(t, goodConfig)

	require.Error(t, doReload(t, cfgFile, tx, a.asReloader(), b.asReloader(), c.asReloader()))

	st := tx.tracker.Get()
	require.False(t, st.LastReloadSuccessful)
	require.Equal(t, reloadstatus.CategoryApply, st.ErrorCategory)
	require.Equal(t, "b", st.FailedReloader)
	require.Equal(t, []string{"a"}, st.AppliedReloaders)
	require.True(t, st.RollbackAttempted)
	require.True(t, st.RollbackSuccessful)

	// 'a' applied then was rolled back to the known-good config.
	require.Same(t, goodConfig, a.configs[len(a.configs)-1])
	// 'c' is after the failing reloader, so it never ran on the second reload.
	require.Len(t, c.configs, 1)
	// A failed reload does not change the last known-good config.
	require.Same(t, goodConfig, tx.lastGood)
}

