func getJSON(t *testing.T, url string) map[string]any {
	t.Helper()
	resp, err := http.Get(url)
	require.NoError(t, err)
	defer resp.Body.Close()
	body, err := io.ReadAll(resp.Body)
	require.NoError(t, err)
	var out map[string]any
	require.NoError(t, json.Unmarshal(body, &out))
	return out
}

func reloadStatusData(t *testing.T, baseURL string) map[string]any {
	t.Helper()
	got := getJSON(t, baseURL+"/api/v1/status/reload")
	require.Equal(t, "success", got["status"])
	data, ok := got["data"].(map[string]any)
	require.True(t, ok, "reload status data: %v", got)
	return data
}

func waitReady(t *testing.T, baseURL string) {
	t.Helper()
	require.Eventually(t, func() bool {
		resp, err := http.Get(baseURL + "/-/ready")
		if err != nil {
			return false
		}
		defer resp.Body.Close()
		return resp.StatusCode == http.StatusOK
	}, 30*time.Second, 200*time.Millisecond, "Prometheus didn't become ready in time")
}

